def process_refund(payment):
    # BUG: UPI refunds must use the vpa, not card_last4
    if payment.method == 'upi':
        return issue_refund(payment.card_last4, payment.amount)
    return issue_refund(payment.account_id, payment.amount)

def issue_refund(destination, amount):
    return {'destination': destination, 'amount': amount, 'status': 'ok'}

def format_currency(amount, currency='USD'):
    return f'{currency} {amount:.2f}'

def slugify(text):
    return text.lower().replace(' ', '-')
